import React from "react";

function Products() {
  const products = [
    { id: 101, name: "Wireless Mouse", category: "Peripherals", total: 50, current: 23 },
    { id: 102, name: "Keyboard", category: "Peripherals", total: 40, current: 3 },
    { id: 103, name: "USB Hub", category: "Accessories", total: 30, current: 4 },
    { id: 104, name: "HDMI Cable", category: "Cables", total: 100, current: 67 },
    { id: 105, name: "Monitor Stand", category: "Furniture", total: 20, current: 5 },
    { id: 106, name: "Laptop Stand", category: "Furniture", total: 35, current: 18 },
  ];

  return (
    <div className="min-h-screen bg-gray-50 p-8">

      {/* Header */}
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-semibold">Products</h1>
        <button className="bg-black text-white px-4 py-2 rounded-lg">
          + Add Product
        </button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-3 gap-4 mb-6">
        <div className="bg-white p-4 rounded-xl shadow">
          <p className="text-gray-500 text-sm">Total Products</p>
          <h2 className="text-2xl font-bold">6</h2>
        </div>

        <div className="bg-white p-4 rounded-xl shadow">
          <p className="text-gray-500 text-sm">Low Stock</p>
          <h2 className="text-2xl font-bold text-red-500">2</h2>
        </div>

        <div className="bg-white p-4 rounded-xl shadow">
          <p className="text-gray-500 text-sm">In Stock</p>
          <h2 className="text-2xl font-bold text-green-600">4</h2>
        </div>
      </div>

      {/* Product Table */}
      <div className="bg-white rounded-xl shadow p-4">
        <table className="w-full text-left">
          <thead>
            <tr className="text-gray-500 border-b">
              <th className="py-3">ID</th>
              <th>Product</th>
              <th>Category</th>
              <th>Total</th>
              <th>Available</th>
              <th>Status</th>
            </tr>
          </thead>

          <tbody>
            {products.map((item) => {
              const low = item.current <= 5;

              return (
                <tr key={item.id} className="border-b hover:bg-gray-50">
                  <td className="py-3">{item.id}</td>
                  <td className="font-medium">{item.name}</td>
                  <td>{item.category}</td>
                  <td>{item.total}</td>
                  <td className={low ? "text-red-500 font-semibold" : ""}>
                    {item.current}
                  </td>
                  <td>
                    <span
                      className={`px-2 py-1 text-sm rounded ${
                        low
                          ? "bg-red-100 text-red-600"
                          : "bg-green-100 text-green-600"
                      }`}
                    >
                      {low ? "Low" : "Available"}
                    </span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

    </div>
  );
}

export default Products;
